const items = $input.all();
return items.map(item => {
  const j = item.json || {};
  const phone = (j.phone === undefined || j.phone === null) ? null : String(j.phone);
  const convIdRaw = j.chatwoot_conversation_id;
  const convId = (convIdRaw === undefined || convIdRaw === null || convIdRaw === '') ? null : parseInt(convIdRaw, 10);
  const inboxIdRaw = j.chatwoot_inbox_id;
  const inboxId = (inboxIdRaw === undefined || inboxIdRaw === null || inboxIdRaw === '') ? null : parseInt(inboxIdRaw, 10);
  const state = (j.state === undefined || j.state === null || j.state === '') ? null : String(j.state);
  const aiEnabled = (j.ai_enabled === undefined || j.ai_enabled === null) ? null : Boolean(j.ai_enabled);
  const humanLocked = (j.human_locked === undefined || j.human_locked === null) ? null : Boolean(j.human_locked);
  const currentFlow = (j.current_flow === undefined || j.current_flow === null || j.current_flow === '') ? null : String(j.current_flow);
  const testRunId = (j.test_run_id === undefined || j.test_run_id === null) ? null : String(j.test_run_id);
  return {
    json: {
      phone,
      chatwoot_conversation_id: convId,
      chatwoot_inbox_id: inboxId,
      state,
      ai_enabled: aiEnabled,
      human_locked: humanLocked,
      current_flow: currentFlow,
      test_run_id: testRunId,
      ai_enabled_param: aiEnabled === null ? null : (aiEnabled ? 'true' : 'false'),
      human_locked_param: humanLocked === null ? null : (humanLocked ? 'true' : 'false')
    }
  };
});

const validated = $('Validate Payload').first().json;
const items = $input.all();
return items.map(item => {
  const j = item.json || {};
  const convId = j.chatwoot_conversation_id || validated.chatwoot_conversation_id;
  return {
    json: {
      chatwoot_conversation_id: convId,
      test_run_id: validated.test_run_id,
      event_payload_json: JSON.stringify({
        test_run_id: validated.test_run_id,
        chatwoot_conversation_id: convId,
        state: validated.state,
        ai_enabled: validated.ai_enabled,
        human_locked: validated.human_locked,
        current_flow: validated.current_flow
      })
    }
  };
});
